package core.applib.org.apache.isis.applib.services.error;

public class ErrorDetails { private final String mainMessage ; private final boolean recognized ; private final boolean authorizationCause ; private final List < String > stackTraceDetailListCombined ; private final List < List < String > > stackDetailListPerCause ; public ErrorDetails ( final String mainMessage , final boolean recognized , final boolean authorizationCause , final List < String > stackTraceDetailListCombined , final List < List < String > > stackDetailListPerCause ) { this . mainMessage = mainMessage ; this . recognized = recognized ; this . authorizationCause = authorizationCause ; this . stackTraceDetailListCombined = stackTraceDetailListCombined ; this . stackDetailListPerCause = stackDetailListPerCause ; } public String getMainMessage ( ) { return mainMessage ; } public boolean isRecognized ( ) { return recognized ; } public boolean isAuthorizationCause ( ) { return authorizationCause ; } @ Deprecated public List < String > getStackTraceDetailList ( ) { return stackTraceDetailListCombined ; } public List < String > getStackTraceDetailCombined ( ) { return stackTraceDetailListCombined ; } public List < List < String > > getStackTraceDetailPerCause ( ) { return stackDetailListPerCause ; } }